const gallery = document.querySelector('[data-gallery]');
const categorySelect = document.querySelector('[data-category]');
const searchInput = document.querySelector('[data-search]');
const modal = document.querySelector('[data-modal]');
const modalTitle = document.querySelector('[data-modal-title]');
const modalFrame = document.querySelector('[data-modal-frame]');
const modalMeta = document.querySelector('[data-modal-meta]');
const toast = document.querySelector('[data-toast]');
let activeHero = HEROES[0];
let viewportMode = 'desktop';

function iframeDoc(hero) {
  return `<!doctype html><html><head><meta name="viewport" content="width=device-width, initial-scale=1" />
  <style>
    *{box-sizing:border-box} body{margin:0;font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:#fff;color:#111827} img{max-width:100%;display:block}
    .hero{min-height:620px;padding:72px 48px;display:grid;grid-template-columns:minmax(0,1fr) minmax(0,1fr);gap:42px;align-items:center;overflow:hidden;position:relative}
    .copy{max-width:620px;position:relative;z-index:2}.pill{display:inline-flex;padding:8px 12px;border-radius:999px;font-size:13px;font-weight:800;margin-bottom:18px}
    h1{font-size:clamp(40px,6vw,76px);line-height:.96;letter-spacing:-.07em;margin:0 0 20px}p{font-size:clamp(17px,2vw,20px);line-height:1.65;margin:0 0 26px;max-width:620px}.actions{display:flex;gap:12px;flex-wrap:wrap;margin-bottom:22px}.actions a{display:inline-flex;align-items:center;justify-content:center;border-radius:999px;background:#111827;color:white;padding:14px 21px;font-weight:850;text-decoration:none}.actions .ghost{background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.14)}ul{display:grid;gap:10px;padding:0;margin:0;list-style:none}li:before{content:'✓';font-weight:900;margin-right:9px}.visual{position:relative}.photo,.visual>img{width:100%;height:auto;object-fit:cover;box-shadow:0 28px 90px rgba(0,0,0,.18)}
    @media (max-width: 760px){.hero{grid-template-columns:1fr;min-height:auto;padding:48px 22px;gap:32px}h1{font-size:42px;letter-spacing:-.05em}.copy{max-width:none}.actions a{width:100%}.h9 .grid{grid-template-columns:1fr!important}}
    ${hero.preview.css}
  </style></head><body>${hero.preview.html}</body></html>`;
}

function writeFrame(frame, hero) {
  frame.srcdoc = iframeDoc(hero);
}

function categories() {
  const cats = ['All', ...new Set(HEROES.map(h => h.category))];
  categorySelect.innerHTML = cats.map(cat => `<option value="${cat}">${cat}</option>`).join('');
}

function filteredHeroes() {
  const query = searchInput.value.trim().toLowerCase();
  const cat = categorySelect.value;
  return HEROES.filter(hero => {
    const haystack = [hero.name, hero.category, ...hero.tags, ...hero.widgets].join(' ').toLowerCase();
    return (cat === 'All' || hero.category === cat) && (!query || haystack.includes(query));
  });
}

function render() {
  const items = filteredHeroes();
  gallery.innerHTML = items.map(hero => `
    <article class="card" data-id="${hero.id}">
      <div class="preview-frame-wrap"><iframe title="${hero.name} preview" loading="lazy"></iframe></div>
      <div class="card-body">
        <div class="card-top"><span>${hero.category}</span><small>${hero.widgets.length} widgets</small></div>
        <h3>${hero.name}</h3>
        <p>${hero.tags.map(t => `#${t}`).join(' ')}</p>
        <div class="badges">${hero.widgets.slice(0,5).map(w => `<em>${w}</em>`).join('')}</div>
        <div class="card-actions">
          <button data-action="preview">Preview</button>
          <button data-action="copy">Copy JSON</button>
          <button data-action="download">Download</button>
        </div>
      </div>
    </article>`).join('');
  document.querySelectorAll('.card').forEach(card => {
    const hero = HEROES.find(h => h.id === card.dataset.id);
    writeFrame(card.querySelector('iframe'), hero);
  });
}

function setModalWidth() {
  modalFrame.className = `modal-frame ${viewportMode}`;
  modal.querySelectorAll('[data-viewport]').forEach(btn => btn.classList.toggle('active', btn.dataset.viewport === viewportMode));
}

function openPreview(hero) {
  activeHero = hero;
  viewportMode = 'desktop';
  modalTitle.textContent = hero.name;
  modalMeta.textContent = `${hero.category} | ${hero.widgets.join(', ')}`;
  writeFrame(modalFrame.querySelector('iframe'), hero);
  setModalWidth();
  modal.showModal();
}

async function copyJson(hero) {
  const text = JSON.stringify(hero.template, null, 2);
  try {
    if (navigator.clipboard?.write) {
      const blob = new Blob([text], {type: 'application/json'});
      const plain = new Blob([text], {type: 'text/plain'});
      await navigator.clipboard.write([new ClipboardItem({'text/plain': plain, 'application/json': blob})]);
    } else {
      await navigator.clipboard.writeText(text);
    }
    showToast(`${hero.name} JSON copied`);
  } catch (error) {
    await navigator.clipboard.writeText(text);
    showToast(`${hero.name} JSON copied as text`);
  }
}

function downloadJson(hero) {
  const text = JSON.stringify(hero.template, null, 2);
  const blob = new Blob([text], {type: 'application/json'});
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `${hero.id}-${hero.name.toLowerCase().replace(/[^a-z0-9]+/g, '-')}.json`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function showToast(message) {
  toast.textContent = message;
  toast.classList.add('show');
  clearTimeout(showToast.timer);
  showToast.timer = setTimeout(() => toast.classList.remove('show'), 1800);
}

gallery.addEventListener('click', event => {
  const button = event.target.closest('button');
  const card = event.target.closest('.card');
  if (!button || !card) return;
  const hero = HEROES.find(h => h.id === card.dataset.id);
  if (button.dataset.action === 'preview') openPreview(hero);
  if (button.dataset.action === 'copy') copyJson(hero);
  if (button.dataset.action === 'download') downloadJson(hero);
});

modal.addEventListener('click', event => {
  if (event.target.dataset.close !== undefined) modal.close();
  if (event.target.dataset.viewport) {
    viewportMode = event.target.dataset.viewport;
    setModalWidth();
  }
  if (event.target.dataset.modalCopy !== undefined) copyJson(activeHero);
  if (event.target.dataset.modalDownload !== undefined) downloadJson(activeHero);
});

searchInput.addEventListener('input', render);
categorySelect.addEventListener('change', render);

categories();
render();
